-- ============================================================
-- Migration 015 — Section 5 content (Locational Influence)
-- Bulk-loads M2-S5-C3 (Estate & Tax) and M2-S5-C4 (Private/
-- Consulting), 10 scenarios per category, 20 total.
--
-- Difficulty distribution (per category):
--   #1, #2  · introductory
--   #3, #4  · basic
--   #5, #6  · intermediate
--   #7, #8  · advanced
--   #9, #10 · expert
--
-- After this migration:
--   - M2-S5-C3 (Estate & Tax) has 10 of 10 scenarios loaded.
--   - M2-S5-C4 (Private/Consulting) has 10 of 10 scenarios loaded.
--   - Section 5 is 4 of 6 categories complete.
--
-- No schema changes. The factor_analysis field type and the six
-- M2-S5 categories were created in Session 1 (migration 013).
-- M2-S5-C1 and M2-S5-C2 were loaded in Session 2 (migration 014).
-- Section-level defaults from Session 1:
--   classification_options = ['Positive','Negative','Neutral','Market-Dependent']
--   min_rationale_chars    = 20
-- These are repeated explicitly in each field_options_override
-- for self-describing scenario rows.
--
-- All scenarios in C3 (Estate & Tax) are retrospective effective-
-- date assignments. context_label = 'Estate Context'.
-- All scenarios in C4 (Private/Consulting) are investor-rental
-- analyses. context_label = 'Consulting Context'.
--
-- Note on M3 #10: source artifact contains an intentional duplicate-
-- label distractor — factor B has the effective-date qualifier and
-- is present (Positive); factor E uses the unqualified label and
-- is absent. Preserved verbatim per locked Session 1 spec.
--
-- Idempotency: this migration runs once and is recorded in the
-- migration tracker by the migration runner.
-- ============================================================

BEGIN;

-- ============================================================
-- M2-S5-C3 — Estate & Tax (10 scenarios)
-- ============================================================

-- ─────────────────────────────────────────────────────
-- Scenario 1: 847 Woodlands Drive, Simpsonville — DOD 8 Months Ago, Stable Conditions
-- Category M2-S5-C3 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '847 Woodlands Drive, Simpsonville — DOD 8 Months Ago, Stable Conditions',
  'You are preparing an estate appraisal at 847 Woodlands Drive, Simpsonville, SC 29681. The subject is 3BR/2BA · 1,880 SF · 2006-built SFR · Woodlands at Fairview. Estate appraisal for federal estate tax filing. Date of death: 8 months ago. Locational analysis must reflect conditions as they existed at the date of death. No significant locational changes are known to have occurred between the date of death and today. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Woodlands Drive, Simpsonville, SC 29681", "subject_summary": "3BR/2BA · 1,880 SF · 2006-built SFR · Woodlands at Fairview", "context_label": "Estate Context", "context_text": "Estate appraisal for federal estate tax filing. Date of death: 8 months ago. Locational analysis must reflect conditions as they existed at the date of death. No significant locational changes are known to have occurred between the date of death and today."}, "location_profile": ["Woodlands at Fairview is a residential subdivision of approximately 210 homes in Simpsonville, southern Greenville County, approximately 11 miles from downtown Greenville. Developed 2003–2010, the neighborhood is fully built out with owner-occupied homes on lots of 0.20–0.32 acres. Internal streets form a loop pattern with several cul-de-sac fingers. An HOA maintains a community greenspace near the entrance.", "847 Woodlands Drive is a cul-de-sac lot on the western edge of the subdivision backing to a maintained HOA buffer that separates the community from a Lowe''s home improvement center approximately 250 feet west. A mature landscape buffer along the HOA strip eliminates direct visibility of the commercial use from the rear yard. The subject is in the Simpsonville/Hillcrest school attendance zone, a documented buyer preference driver. FEMA Zone X is confirmed. No changes in locational conditions are documented between the date of death 8 months ago and today."], "factors": [{"id": "A", "label": "Cul-de-sac location"}, {"id": "B", "label": "Backing to HOA buffer (commercial screened)"}, {"id": "C", "label": "Proximity to commercial use (screened, ~250 ft)"}, {"id": "D", "label": "Desirable school district (Simpsonville/Hillcrest)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Corner lot"}, {"id": "G", "label": "Transmission line easement"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Establish the effective-date baseline. When locational conditions have not changed between the date of death and today, the retrospective analysis produces the same results as a current analysis. The discipline of confirming no changes occurred is itself an analytical step — students must verify stability, not merely assume it.", "Teaching Point 2 — Neutral requires identification even when conditions are unchanged. Factor C (screened commercial) must be identified as present at the date of death regardless of the time elapsed. The factor existed then as it does now and must appear in the retrospective locational analysis. Omitting it because it has no adjustment impact is a reporting error.", "Teaching Point 3 — Short retrospective periods are not automatically simple. Even an 8-month look-back requires the appraiser to confirm that no relevant changes occurred. New construction, road projects, zoning changes, or land use shifts within 8 months are possible. The discipline is the same regardless of how short the look-back period is."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "The subject is at the end of a cul-de-sac with minimal through-traffic. This condition existed at the date of death 8 months ago, the same as today."}, "B": {"present": true, "classification": "Positive", "rationale": "The HOA buffer with mature landscaping eliminated rear visibility of the Lowe''s at the date of death — same condition as today. A positive locational attribute."}, "C": {"present": true, "classification": "Neutral", "rationale": "The commercial use was present at the date of death and is screened by the HOA buffer. The mitigation renders the influence market-neutral — but it must still be identified and disclosed."}, "D": {"present": true, "classification": "Positive", "rationale": "The school zone was the same at the date of death as today and is a documented buyer preference driver in this submarket."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X was confirmed at the date of death. No flood insurance was required at the effective date."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 1;

-- ─────────────────────────────────────────────────────
-- Scenario 2: 2214 Hillcrest Road, Greer — DOD 16 Months Ago, Gas Station Closed Post-Death
-- Category M2-S5-C3 #2 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'introductory',
  '2214 Hillcrest Road, Greer — DOD 16 Months Ago, Gas Station Closed Post-Death',
  'You are preparing an estate appraisal at 2214 Hillcrest Road, Greer, SC 29651. The subject is 3BR/2BA · 1,740 SF · 2001-built SFR · Hillcrest Terrace. Estate appraisal for estate settlement and equitable distribution among heirs. Date of death: 16 months ago. Locational analysis must reflect conditions as of the date of death. A gas station/convenience store that operated on a nearby corner closed approximately 6 months after the date of death and the site has since been remediated. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2214 Hillcrest Road, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,740 SF · 2001-built SFR · Hillcrest Terrace", "context_label": "Estate Context", "context_text": "Estate appraisal for estate settlement and equitable distribution among heirs. Date of death: 16 months ago. Locational analysis must reflect conditions as of the date of death. A gas station/convenience store that operated on a nearby corner closed approximately 6 months after the date of death and the site has since been remediated."}, "location_profile": ["Hillcrest Terrace is a residential subdivision of approximately 175 homes in Greer, northern Greenville County, approximately 5 miles from downtown Greer. Developed 1997–2004, the neighborhood is owner-occupied with mature landscaping. Streets form a loop pattern with one entrance off Hillcrest Road.", "2214 Hillcrest Road is a through-street lot with 0.22 acres. A gas station and convenience store operated on the corner of Hillcrest Road and Wade Hampton Boulevard approximately 180 feet from the subject at the date of death — generating traffic noise, light spillover, and periodic fuel delivery activity observable from the subject''s front yard. That operation closed approximately 6 months after the date of death and the site has since been remediated to a vacant commercial lot. The subject is in the Greer/Eastside school attendance zone, above-average in Greenville County. FEMA Zone X is confirmed."], "factors": [{"id": "A", "label": "Gas station / convenience store (~180 ft — operating at date of death)"}, {"id": "B", "label": "Through-street location"}, {"id": "C", "label": "Greer/Eastside school district (above average)"}, {"id": "D", "label": "FEMA Zone X"}, {"id": "E", "label": "Established neighborhood with mature landscaping"}, {"id": "F", "label": "Remediated vacant commercial lot (current condition — not present at date of death)"}, {"id": "G", "label": "HOA common area backing"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — The key distractor is a condition that improved after the date of death. Factor F (remediated vacant lot) represents the current condition of the former gas station site. Students who check Factor F are describing what the location looks like today, not what it looked like 16 months ago at the date of death. In estate appraisal, the effective date controls every locational determination.", "Teaching Point 2 — Subsequent improvements do not retroactively eliminate prior negatives. The gas station closure and remediation does not change the fact that at the date of death, the station was operating and its negative impacts were present. Heirs who benefit from the improvement must not see that benefit retroactively applied to the estate value — it belongs to the current period, not the decedent''s estate.", "Teaching Point 3 — Both through-street and gas station are Negative and must appear. Students who identify only the gas station (the obvious claim factor) and miss the through-street location are providing an incomplete locational profile. Both factors were present at the date of death and both affect value. Completeness is a USPAP obligation regardless of the assignment type."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "The gas station was in active operation at the date of death, generating traffic noise, light spillover, and fuel delivery activity observable from the subject. A Negative condition that existed at the effective date must be analyzed regardless of subsequent changes."}, "B": {"present": true, "classification": "Negative", "rationale": "The subject is on a through-street — a modest Negative relative to cul-de-sac configurations. This condition was present at the date of death and is unchanged today."}, "C": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive buyer reception — same school zone at the date of death as today."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed at the date of death."}, "E": {"present": true, "classification": "Positive", "rationale": "Fully built out with stable owner-occupancy and mature landscaping at the date of death — a positive relative to active construction areas."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 2;

