-- Scenario 3: 418 Camellia Court, Spartanburg — DOD 3 Years Ago, Adjacent Vacant Commercial Zoning
-- Category M2-S5-C3 #3 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'basic',
  '418 Camellia Court, Spartanburg — DOD 3 Years Ago, Adjacent Vacant Commercial Zoning',
  'You are preparing an estate appraisal at 418 Camellia Court, Spartanburg, SC 29301. The subject is 4BR/2BA · 2,040 SF · 2009-built SFR · Camellia Ridge. Estate appraisal for federal estate tax filing. Date of death: 3 years ago. A large retail shopping center on an adjacent parcel opened approximately 20 months ago — approximately 16 months after the date of death. The locational profile at the date of death must be analyzed based on conditions that existed at that time. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "418 Camellia Court, Spartanburg, SC 29301", "subject_summary": "4BR/2BA · 2,040 SF · 2009-built SFR · Camellia Ridge", "context_label": "Estate Context", "context_text": "Estate appraisal for federal estate tax filing. Date of death: 3 years ago. A large retail shopping center on an adjacent parcel opened approximately 20 months ago — approximately 16 months after the date of death. The locational profile at the date of death must be analyzed based on conditions that existed at that time."}, "location_profile": ["Camellia Ridge is a residential subdivision of approximately 195 homes in western Spartanburg, developed 2005–2012. Lots average 0.24 acres. The subdivision backs along its southern edge to a large commercially-zoned parcel that was vacant and zoned commercial at the date of death 3 years ago. That parcel has since been developed into a 180,000 SF regional retail center with a grocery anchor, which opened approximately 20 months ago.", "418 Camellia Court is a cul-de-sac lot on the southern edge of the subdivision. At the date of death, the rear of the subject lot backed to the vacant commercially-zoned parcel — no structures, no activity, but commercial zoning was documented in county records. The Boiling Springs school district applied at the date of death, the same as today. FEMA Zone X was confirmed at the date of death. I-85 access is approximately 2 miles south via SC-9 — a positive regional connectivity attribute that existed at the date of death."], "factors": [{"id": "A", "label": "Backing to vacant commercially-zoned parcel (condition at date of death)"}, {"id": "B", "label": "Cul-de-sac location"}, {"id": "C", "label": "Boiling Springs school district (top-rated in county)"}, {"id": "D", "label": "FEMA Zone X"}, {"id": "E", "label": "I-85 regional access (~2 miles, SC-9)"}, {"id": "F", "label": "Backing to large retail center (current condition — not present at date of death)"}, {"id": "G", "label": "Railroad proximity"}, {"id": "H", "label": "HOA greenspace backing"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Zoning is a locational condition at the effective date. Commercial zoning on the adjacent parcel was documented at the date of death, even though the parcel was vacant. Commercially-zoned land adjacent to residential use is a Negative regardless of whether development has begun — buyers recognize the potential for future use changes. This condition must be identified and classified as of the date of death.", "Teaching Point 2 — The retail center is a distractor. Factor F represents a condition that did not exist at the date of death. A retail center that opened 20 months ago — 16 months after the date of death — has no place in the retrospective locational analysis. Students who check F are applying current observations to an effective-date assignment, which produces an overstated or understated value and is analytically indefensible.", "Teaching Point 3 — Vacant land zoning vs. developed use. Students may be tempted to classify Factor A as Neutral because the parcel was vacant and undeveloped. But zoning is a documented condition, not a speculative one. Sophisticated buyers and their agents investigate zoning before purchase. Commercial zoning adjacency affects buyer pool depth and pricing regardless of current development status."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "At the date of death, the rear lot line backed to a vacant parcel with documented commercial zoning. Commercial zoning adjacency — even without active development — is a Negative for residential buyers who recognize the potential for future commercial intrusion. The current retail development is irrelevant to this effective-date analysis."}, "B": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus with minimal through-traffic at the date of death — same configuration as today."}, "C": {"present": true, "classification": "Positive", "rationale": "Top-rated in Spartanburg County at the date of death — documented buyer preference driver, same zone as today."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed at the date of death."}, "E": {"present": true, "classification": "Positive", "rationale": "I-85 access within 2 miles provided strong regional connectivity at the date of death — same condition as today."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 3;

