-- Scenario 4: 1847 Fox Run Drive, Duncan — DOD 4 Years Ago, Pre-Redistricting Dorman Zone
-- Category M2-S5-C3 #4 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 4,
  'basic',
  '1847 Fox Run Drive, Duncan — DOD 4 Years Ago, Pre-Redistricting Dorman Zone',
  'You are preparing an estate appraisal at 1847 Fox Run Drive, Duncan, SC 29334. The subject is 3BR/2BA · 1,680 SF · 2007-built SFR · Fox Run Estates. Estate appraisal for estate settlement. Date of death: 4 years and 3 months ago. A school district attendance zone redistribution by Spartanburg County School District 5 took effect approximately 2 years ago — approximately 2 years and 3 months after the date of death. At the date of death, the subject was in a different school zone than it is today. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1847 Fox Run Drive, Duncan, SC 29334", "subject_summary": "3BR/2BA · 1,680 SF · 2007-built SFR · Fox Run Estates", "context_label": "Estate Context", "context_text": "Estate appraisal for estate settlement. Date of death: 4 years and 3 months ago. A school district attendance zone redistribution by Spartanburg County School District 5 took effect approximately 2 years ago — approximately 2 years and 3 months after the date of death. At the date of death, the subject was in a different school zone than it is today."}, "location_profile": ["Fox Run Estates is a residential subdivision of approximately 155 homes in Duncan, Spartanburg County, developed 2004–2011. Lots average 0.22 acres. Streets form a loop pattern with cul-de-sac fingers. The subdivision is served by an HOA that maintains a community play area and entrance landscaping.", "1847 Fox Run Drive is a cul-de-sac lot. At the date of death 4 years and 3 months ago, the subject was assigned to Dorman High School — the highest-rated high school in Spartanburg County District 5, widely cited as a buyer preference driver in this submarket. A redistribution that took effect approximately 2 years ago reassigned the subject to a different high school with a shorter performance record. The current school zone is NOT the zone applicable at the date of death. FEMA Zone X is confirmed. A Duke Energy transmission line easement runs along the northern edge of the subdivision approximately 250 feet from the subject lot — not directly adjacent."], "factors": [{"id": "A", "label": "Dorman High School attendance zone (condition at date of death)"}, {"id": "B", "label": "Cul-de-sac location"}, {"id": "C", "label": "HOA community amenities (play area, entrance landscaping)"}, {"id": "D", "label": "Transmission line easement (northern subdivision edge, ~250 ft from subject)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Current school attendance zone (post-redistribution — not applicable at date of death)"}, {"id": "G", "label": "Industrial use adjacency"}, {"id": "H", "label": "Gas station or commercial nuisance"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — School district at the effective date, not today. At the date of death, the subject was in the Dorman zone — a Positive. Today it is in a different, lower-track zone. Students who classify the current school zone are analyzing the wrong effective date. The estate is valued as of the date of death; the school zone that applies is the one that existed then.", "Teaching Point 2 — Distance attenuates transmission line impact. Factor D requires careful reading: the easement is 250 feet away along the subdivision''s northern edge, with intervening lots. Students who classify it as Negative based on the general category of ''transmission line'' without accounting for distance are applying a rule rather than performing analysis. Neutral is correct when market evidence does not support a detectable price effect at this distance.", "Teaching Point 3 — The current school zone (F) is the key distractor. Students who check F may be using current knowledge — perhaps they know the current zone or have looked it up. The obligation is to analyze conditions as of the date of death, not as of today. Every factor identification must be grounded in historical evidence available at or before the effective date."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "At the date of death, the subject was in the Dorman High School zone — the highest-rated school in District 5 and a documented buyer preference driver. This was the applicable school condition at the effective date and must be analyzed accordingly."}, "B": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus at the date of death — same configuration as today."}, "C": {"present": true, "classification": "Positive", "rationale": "HOA-maintained community amenities provided a modest positive locational attribute at the date of death — same conditions as today."}, "D": {"present": true, "classification": "Neutral", "rationale": "The transmission easement runs along the subdivision''s northern edge approximately 250 feet from the subject lot — not directly adjacent. At this distance with intervening lots, market impact is attenuated to the point of no detectable price effect — Neutral."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed at the date of death."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 4;

