INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3312 Augusta Road, Greenville, SC 29605", "subject_summary": "3BR/2BA · 1,580 SF · 1988-built SFR (updated 2012) · Augusta Road Corridor", "context_label": "Estate Context", "context_text": "Estate appraisal for estate tax filing. Date of death: 6 years ago. The Augusta Road corridor has experienced significant reinvestment since the date of death. At the date of death, the corridor was characterized by a mix of older residential properties, marginal commercial tenants, and several long-vacant storefronts. The appraiser must analyze conditions as they existed 6 years ago, not today."}, "location_profile": ["The subject is a single-family residence on Augusta Road in Greenville, approximately 1.5 miles southwest of downtown. Six years ago at the date of death, the corridor was an older residential and commercial mixed-use area with variable occupancy in commercial properties. Several storefronts within 0.3 miles were vacant at that time, documented in period aerial photography and MLS records showing limited investor activity.", "At the date of death, the subject fronted directly on Augusta Road with a 24-foot setback. Augusta Road carried moderate arterial traffic. The adjacent parcel to the south was a vacant commercial building with boarded windows at the date of death — the same condition described in prior scenarios in this module. The applicable school zone 6 years ago was a below-average Greenville County attendance zone — the same zone as today. Downtown Greenville was approximately 1.5 miles away; at the date of death, the downtown amenity corridor was substantially less developed than today. FEMA Zone X confirmed at the date of death."], "factors": [{"id": "A", "label": "Augusta Road arterial frontage (24-ft setback, moderate traffic at date of death)"}, {"id": "B", "label": "Adjacent vacant/blighted commercial building (condition at date of death)"}, {"id": "C", "label": "Corridor vacancy / marginal commercial tenancy (condition at date of death)"}, {"id": "D", "label": "Downtown Greenville proximity (3 miles — buyer response at date of death)"}, {"id": "E", "label": "Below-average school district"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "Current reinvested corridor character (post-death condition — not applicable at effective date)"}, {"id": "H", "label": "Premium school district"}, {"id": "I", "label": "HOA amenity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Corridor character at the effective date requires historical documentation. Factor G (current reinvested character) is the key distractor. The corridor''s current vitality does not exist at the date of death and cannot be applied retroactively. Students must ground each corridor-related factor in period-specific evidence: aerial photography, MLS records, county permit data, and contemporaneous market reports from 6 years ago.", "Teaching Point 2 — Multiple negatives must all be identified. Three Negative factors (A, B, C) coexist in this scenario alongside one Market-Dependent (D). Students who identify only the most obvious negative (arterial frontage or blighted adjacency) are producing an incomplete locational profile. In estate appraisal, an incomplete retrospective analysis is a USPAP scope of work failure.", "Teaching Point 3 — Downtown proximity is Market-Dependent at the effective date, not Positive. Applying today''s understanding of downtown Greenville''s amenity value to conditions 6 years ago is a common retrospective error. The appraiser must ask what market evidence showed at the effective date — not what the market shows today. Period MLS data and buyer agent interviews from that time are the appropriate sources."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a moderate arterial at a 24-foot setback was a Negative at the date of death. Traffic, noise, and commercial character concerns existed at the effective date — same physical condition as today, though traffic volumes and corridor character may have changed."}, "B": {"present": true, "classification": "Negative", "rationale": "The adjacent property was a vacant, boarded commercial building at the date of death. This proximity externality existed at the effective date and is a documented Negative for residential value at that time."}, "C": {"present": true, "classification": "Negative", "rationale": "Several vacant storefronts within 0.3 miles and marginal commercial tenancy were documented conditions at the date of death — a Negative for residential buyers evaluating neighborhood stability at that time."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "Six years ago, downtown Greenville was less developed as a residential amenity destination. Buyer response to downtown proximity at that time was split — some valued the connectivity; others discounted the corridor''s instability. Market-Dependent is appropriate for effective-date conditions."}, "E": {"present": true, "classification": "Negative", "rationale": "The below-average school zone was documented at the date of death and is a Negative for family buyers — same zone as today."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of death — confirmed by FEMA maps applicable at that time."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 5;

