-- Scenario 6: 2118 Pelham Road, Greenville — DOD 9 Years Ago, Pre-Patewood-Expansion Corridor
-- Category M2-S5-C3 #6 · difficulty 'intermediate'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 6,
  'intermediate',
  '2118 Pelham Road, Greenville — DOD 9 Years Ago, Pre-Patewood-Expansion Corridor',
  'You are preparing an estate appraisal at 2118 Pelham Road, Greenville, SC 29615. The subject is 4BR/2.5BA · 2,220 SF · 1999-built SFR · Pelham Place. Estate appraisal for estate tax filing. Date of death: 9 years ago. The Pelham Road corridor has changed substantially since the date of death — significant medical office development near Patewood Medical Campus and retail expansion have increased the positive employment and convenience attributes of this corridor over the past 9 years. The effective-date conditions must be established using historical evidence. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2118 Pelham Road, Greenville, SC 29615", "subject_summary": "4BR/2.5BA · 2,220 SF · 1999-built SFR · Pelham Place", "context_label": "Estate Context", "context_text": "Estate appraisal for estate tax filing. Date of death: 9 years ago. The Pelham Road corridor has changed substantially since the date of death — significant medical office development near Patewood Medical Campus and retail expansion have increased the positive employment and convenience attributes of this corridor over the past 9 years. The effective-date conditions must be established using historical evidence."}, "location_profile": ["Pelham Place is a residential subdivision of approximately 145 homes on Pelham Road in northeastern Greenville County, approximately 6 miles from downtown. The subdivision was fully built out by 2002 and has been stable owner-occupied throughout. At the date of death 9 years ago, the Pelham Road corridor had fewer medical offices and retail options than today — the Patewood Medical Campus was operating but smaller, and the retail corridor on Pelham Road was less developed.", "2118 Pelham Road is a through-street lot with direct Pelham Road frontage and a 38-foot setback. At the date of death, Pelham Road carried moderate traffic — less than today, as subsequent commercial and medical development has increased volume since the effective date. The school zone applicable at the date of death was the Eastside/Blue Ridge zone, above-average in Greenville County — same as today. FEMA Zone X confirmed at the date of death. Prisma Health Patewood Medical Campus was operational 9 years ago but smaller; the employment driver existed at the date of death, though its scale was different."], "factors": [{"id": "A", "label": "Pelham Road frontage with moderate traffic (condition at date of death)"}, {"id": "B", "label": "Eastside/Blue Ridge school district (above average — same at date of death)"}, {"id": "C", "label": "FEMA Zone X"}, {"id": "D", "label": "Established neighborhood stability (fully built out, owner-occupied)"}, {"id": "E", "label": "Patewood Medical Campus employment proximity (operational but smaller at date of death)"}, {"id": "F", "label": "Current Pelham Road retail and medical office expansion (post-death condition)"}, {"id": "G", "label": "Cul-de-sac location"}, {"id": "H", "label": "Adjacent commercial nuisance or blight"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Scale matters in retrospective employment analysis. Factor E (Patewood proximity) existed at the date of death but at a different scale than today. Students who classify it as Positive based on the current campus size are applying today''s evidence. The correct approach uses sales data from the effective-date period to establish how the market priced proximity to the campus as it existed 9 years ago.", "Teaching Point 2 — Current corridor growth is the key distractor. Factor F represents post-death development that did not exist at the effective date. Students who apply current Pelham Road retail and medical density to a 9-year-ago assignment are systematically overstating the before-condition locational positives — producing a higher estate value than is supportable.", "Teaching Point 3 — Stable neighborhood character can be confirmed across time. Factor D (established stability) is one condition that can be confirmed as consistent across the retrospective period because build-out and owner-occupancy are documented in historical records. Not all conditions require significant research — the discipline is to verify each one, not to assume all conditions are the same as today."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Direct frontage on Pelham Road with a 38-foot setback was a Negative at the date of death — arterial noise and commercial character concerns existed at the effective date, though traffic volume was lower than today."}, "B": {"present": true, "classification": "Positive", "rationale": "The same above-average school zone that applies today was applicable at the date of death — a documented Positive in this submarket."}, "C": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of death."}, "D": {"present": true, "classification": "Positive", "rationale": "The subdivision was fully built out and owner-occupied at the date of death — a positive relative to active construction zones."}, "E": {"present": true, "classification": "Market-Dependent", "rationale": "The Medical Campus existed at the date of death but was smaller in scale. The employment driver was present but less pronounced. Market-Dependent is appropriate — direction requires paired sales from the applicable period to establish the magnitude of buyer response at that time."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 6;

