SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "4417 Highway 29 North, Inman, SC 29349", "subject_summary": "3BR/2BA · 1,520 SF · 1985-built SFR (updated 2008) · Rural Spartanburg County · 0.75 acres", "context_label": "Estate Context", "context_text": "Estate appraisal for estate tax filing. Date of death: 13 years ago. A major SCDOT interchange improvement project on I-26 at Highway 29 was completed approximately 8 years ago — approximately 5 years after the date of death. At the date of death, the interchange was a signalized at-grade crossing with no on/off ramp structure. The current full interchange did not exist at the effective date."}, "location_profile": ["The subject is a single-family residence on Highway 29 North in Inman, Spartanburg County, approximately 12 miles northwest of downtown Spartanburg. Highway 29 is a state two-lane highway at this location. At the date of death 13 years ago, the I-26 crossing at Highway 29 was a signalized at-grade intersection — regional access was slower and less direct than today. The full interchange was not constructed until approximately 5 years after the date of death.", "At the date of death, the subject fronted on Highway 29 with a 30-foot setback. Highway 29 carried moderate through-traffic at that time. A small industrial equipment storage yard operated on the parcel immediately north of the subject at the date of death — documented in county records and period aerial photography. This operation closed approximately 6 years ago. The Cherokee County school district applied at the date of death — a small rural district with limited programming relative to Spartanburg County alternatives. Private well and septic served the property at the date of death, the same as today. FEMA Zone X is confirmed."], "factors": [{"id": "A", "label": "Highway 29 frontage (30-ft setback, through-traffic at date of death)"}, {"id": "B", "label": "Industrial equipment storage yard immediately north (condition at date of death)"}, {"id": "C", "label": "At-grade I-26 crossing — limited regional access (condition at date of death)"}, {"id": "D", "label": "Private well and septic"}, {"id": "E", "label": "Small rural school district (limited programming at date of death)"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "Full I-26 interchange (current condition — not present at date of death)"}, {"id": "H", "label": "Remediated/vacant adjacent parcel (current condition — not present at date of death)"}, {"id": "I", "label": "HOA amenity or greenspace"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Infrastructure improvements after the date of death are distractors. Both Factor G (full interchange) and Factor H (remediated parcel) represent conditions that did not exist at the date of death. The at-grade crossing and the active industrial operation are the correct effective-date conditions. Students who check G or H are systematically understating the negative conditions that existed at the effective date, which would overstate estate value.", "Teaching Point 2 — Regional access must be analyzed at its effective-date level. Factor C (at-grade crossing) illustrates a critical retrospective skill: transportation infrastructure changes over time. The appraiser must research what access conditions existed at the date of death — not what currently exists. SCDOT project records, historical aerial photography, and period MLS data are the primary sources.", "Teaching Point 3 — Multiple negatives define the effective-date locational profile. Four Negative factors (A, B, C, E) characterize this effective-date location — a substantially more constrained profile than the current location enjoys. This demonstrates why retrospective analysis matters: applying today''s improved conditions would materially overstate the estate value and produce an indefensible tax filing."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a state highway with a 30-foot setback was a Negative at the date of death — through-traffic noise and lack of residential privacy existed at that time."}, "B": {"present": true, "classification": "Negative", "rationale": "The adjacent industrial storage operation was active at the date of death, documented in county records and aerial photography. An active industrial adjacency at zero separation is a Negative that existed at the effective date and must be analyzed accordingly."}, "C": {"present": true, "classification": "Negative", "rationale": "At the date of death, I-26 access via Highway 29 required a signalized at-grade crossing — slower and less convenient than a full interchange. This constraint existed at the effective date and limited the positive connectivity attribute compared to today."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "In a rural Spartanburg County market, private utilities are the norm. Market-Dependent is appropriate — direction requires paired rural sales from the effective-date period."}, "E": {"present": true, "classification": "Negative", "rationale": "Cherokee County schools with limited programming were a documented Negative for family buyers at the date of death — same district as today."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of death."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 7;

