  '1234 River Road, Greer — DOD 10 Years Ago, Mixed-Direction Changes',
  'You are preparing an estate appraisal at 1234 River Road, Greer, SC 29651. The subject is 4BR/3BA · 2,380 SF · 1994-built SFR · River Road Estates. Estate appraisal for estate tax filing and potential beneficiary dispute. Date of death: 10 years ago. Conditions have changed in mixed directions since the date of death — some locational factors have improved, others have deteriorated. The appraiser must identify and classify each factor as it existed at the effective date, distinguishing current conditions carefully. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1234 River Road, Greer, SC 29651", "subject_summary": "4BR/3BA · 2,380 SF · 1994-built SFR · River Road Estates", "context_label": "Estate Context", "context_text": "Estate appraisal for estate tax filing and potential beneficiary dispute. Date of death: 10 years ago. Conditions have changed in mixed directions since the date of death — some locational factors have improved, others have deteriorated. The appraiser must identify and classify each factor as it existed at the effective date, distinguishing current conditions carefully."}, "location_profile": ["River Road Estates is a residential subdivision of approximately 110 homes near the Tyger River in northern Greenville County, developed 1991–1998. At the date of death 10 years ago, the subdivision was well-maintained and owner-occupied. The Greer/Eastside school zone applied then — same as today. Lake Robinson, a Greer CPW recreational reservoir, was accessible via a public boat landing approximately 0.8 miles from the subject at the date of death.", "At the date of death, the subject lot backed to undeveloped wooded acreage that provided a natural privacy buffer. That wooded parcel has since been developed into a townhome community — development began approximately 5 years after the date of death. At the date of death, a small neighborhood convenience store operated approximately 0.3 miles south on River Road — a modest commercial use generating occasional traffic. That store closed approximately 7 years ago. River Road itself carried light rural traffic at the date of death. FEMA Zone X confirmed at the date of death. No HOA existed at the date of death."], "factors": [{"id": "A", "label": "Wooded rear acreage privacy buffer (condition at date of death)"}, {"id": "B", "label": "Lake Robinson recreational access (0.8 miles at date of death)"}, {"id": "C", "label": "Convenience store proximity (0.3 miles south — operating at date of death)"}, {"id": "D", "label": "Greer/Eastside school district (above average — same at date of death)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Light rural traffic on River Road (condition at date of death)"}, {"id": "G", "label": "Townhome development backing (current condition — not present at date of death)"}, {"id": "H", "label": "Closed convenience store / vacant parcel (current condition — not present at date of death)"}, {"id": "I", "label": "Transmission line or industrial adjacency"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Conditions that have deteriorated since the date of death must not be imported. Factor G (townhome development) represents a condition that worsened from the estate''s perspective after the death — the wooded privacy buffer was lost. Students who check G and classify it as Negative are describing a current condition that did not exist at the date of death. The retrospective analysis must capture the positive wooded buffer (Factor A) that existed then.", "Teaching Point 2 — Conditions that have improved since the date of death also must not be imported. Factor H (closed store) represents an improvement from the residential perspective — a modest nuisance was removed. But at the date of death the store was operating. The convenience store must be identified as present and classified as Neutral based on its actual impact at the effective date.", "Teaching Point 3 — Mixed-direction changes require heightened discipline. When some conditions have improved and others have deteriorated since the date of death, students face pressure to select the set of conditions that produces the most favorable result for a particular party. The only defensible approach is to identify each factor as it existed at the effective date, supported by historical documentation, without regard to direction."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "At the date of death, the subject backed to undeveloped wooded acreage — a natural privacy buffer that was a documented positive for buyers valuing rear-yard seclusion at that time. This condition no longer exists today, which is irrelevant to the effective-date analysis."}, "B": {"present": true, "classification": "Positive", "rationale": "Public lake access within 0.8 miles was a positive amenity at the date of death — same access point exists today."}, "C": {"present": true, "classification": "Neutral", "rationale": "A small convenience store 0.3 miles south generating occasional traffic was present at the date of death. At this distance with no direct adjacency or audible impact, Neutral is the appropriate classification."}, "D": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive reception — applicable at the date of death, same as today."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of death."}, "F": {"present": true, "classification": "Positive", "rationale": "Light rural traffic at the date of death contributed to a quiet residential character — a modest positive relative to higher-traffic settings in this market context."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 8;

