INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Poinsett Highway, Greenville, SC 29609", "subject_summary": "3BR/2BA · 1,360 SF · 1955-built SFR (updated 2006) · Poinsett Highway Corridor", "context_label": "Estate Context", "context_text": "Estate appraisal for estate tax filing. Date of death: 15 years ago. The Poinsett Highway corridor has changed substantially in both directions over 15 years. At the date of death, the area was characterized by active industrial tenants, low residential reinvestment, and a corridor in measurable decline. Multiple conditions have changed since the effective date. Each factor must be established using period-specific documentation."}, "location_profile": ["The subject is on Poinsett Highway in northern Greenville, approximately 3 miles from downtown. At the date of death 15 years ago, the corridor was characterized by active light-industrial tenants, older commercial buildings with variable occupancy, and limited residential reinvestment. An auto repair cluster operated within 0.2 miles of the subject at the date of death. Downtown Greenville was approximately 3 miles away but, 15 years ago, offered substantially fewer amenities than today.", "At the date of death, the subject fronted on Poinsett Highway with a 20-foot setback. Highway traffic was moderate at that time. The applicable school zone 15 years ago was below-average for Greenville County — same zone as today. FEMA Zone X has been confirmed at the date of death and today. The Swamp Rabbit Trail, which runs approximately 0.5 miles from the current subject location, was not open 15 years ago — it was completed approximately 11 years ago. A neighborhood pharmacy operated 0.2 miles north at the date of death; it closed approximately 8 years ago. No HOA existed."], "factors": [{"id": "A", "label": "Active industrial/auto repair cluster (~0.2 miles — condition at date of death)"}, {"id": "B", "label": "Poinsett Highway frontage (20-ft setback — condition at date of death)"}, {"id": "C", "label": "Below-average school district (same at date of death)"}, {"id": "D", "label": "Downtown Greenville proximity (3 miles — buyer response 15 years ago)"}, {"id": "E", "label": "Corridor in measurable decline — low reinvestment (condition at date of death)"}, {"id": "F", "label": "Neighborhood pharmacy (0.2 miles north — operating at date of death)"}, {"id": "G", "label": "FEMA Zone X"}, {"id": "H", "label": "Swamp Rabbit Trail proximity (current condition — not present at date of death)"}, {"id": "I", "label": "Current corridor reinvestment / renovation activity (post-death condition)"}, {"id": "J", "label": "HOA or common area amenity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — The Swamp Rabbit Trail is the key distractor. The Trail opened approximately 11 years ago — 4 years after the date of death. It does not exist at the effective date and cannot be identified as a present factor. Students who check Factor H are applying a highly visible current amenity to a date when it simply did not exist. In expert-level estate assignments, students must research infrastructure opening dates, not assume current amenities existed at prior effective dates.", "Teaching Point 2 — A declining corridor is itself a locational factor. Factor E identifies not a specific nuisance but a market-area trend: measurable corridor decline. Trend analysis is a legitimate and important locational factor that affects buyer pool depth, price stability, and comparable selection. Students who identify only specific nuisances (A, B) without identifying the overarching market-area trajectory are missing a dimension of the locational profile.", "Teaching Point 3 — Positive conditions at the effective date must also be identified. Factor F (operating pharmacy) is a positive condition that existed 15 years ago and has since been lost. Students who omit it because it no longer exists are conflating current observation with historical analysis. A complete retrospective profile includes all conditions — positive and negative — as they existed at the effective date."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "An active auto repair cluster within 0.2 miles was a documented Negative at the date of death — noise, traffic, and commercial-industrial character contributed to buyer resistance at the effective date."}, "B": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a state highway at 20 feet was a Negative at the date of death — same physical condition as today."}, "C": {"present": true, "classification": "Negative", "rationale": "Below-average school zone documented at the date of death — same zone then as today."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "Downtown Greenville was 3 miles away 15 years ago but far less developed as an amenity destination. Buyer response was split — Market-Dependent is appropriate for the effective-date conditions. Classifying this as Positive would apply today''s downtown value to conditions that did not exist at the date of death."}, "E": {"present": true, "classification": "Negative", "rationale": "The corridor showed measurable decline 15 years ago, documented in period vacancy records, MLS data, and permit activity. A corridor trending downward at the effective date is a Negative separate from any specific nuisance — it affects buyer confidence and comparable pool depth."}, "F": {"present": true, "classification": "Positive", "rationale": "A functioning neighborhood pharmacy within 0.2 miles provided a convenience amenity at the date of death. This condition existed at the effective date and must be analyzed. The pharmacy closed 8 years ago — that subsequent change is irrelevant to the retrospective analysis."}, "G": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of death."}, "H": {"present": false}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 9;

-- ─────────────────────────────────────────────────────
-- Scenario 10: 3318 Wade Hampton Boulevard, Taylors — DOD 18 Years Ago, IRS Challenge Defense
-- Category M2-S5-C3 #10 · difficulty 'expert'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 10,
  'expert',
  '3318 Wade Hampton Boulevard, Taylors — DOD 18 Years Ago, IRS Challenge Defense',
  'You are preparing an estate appraisal at 3318 Wade Hampton Boulevard, Taylors, SC 29687. The subject is 4BR/2BA · 2,100 SF · 1968-built SFR (updated 2001) · Wade Hampton Corridor. Estate appraisal for estate tax filing challenged by IRS. Date of death: 18 years ago. The IRS has challenged the original estate tax filing, claiming undervaluation. The appraiser has been retained to prepare a retrospective locational analysis supporting a defensible effective-date value. Eighteen years of corridor change must be carefully filtered to reflect only what existed at the date of death. Section 5 — Locational Influence — requires you to identify which locational factors were present at the subject as of the effective date, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence as it existed at that date, and write a brief market-supported rationale for each classification. The fundamental discipline of retrospective appraisal is that every factor identification must be grounded in evidence available at or before the effective date — current conditions are distractors. Factors that did not exist at the effective date must be left unchecked, and each rationale must cite specific period-appropriate evidence.'
FROM scenario_categories WHERE code = 'M2-S5-C3';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3318 Wade Hampton Boulevard, Taylors, SC 29687", "subject_summary": "4BR/2BA · 2,100 SF · 1968-built SFR (updated 2001) · Wade Hampton Corridor", "context_label": "Estate Context", "context_text": "Estate appraisal for estate tax filing challenged by IRS. Date of death: 18 years ago. The IRS has challenged the original estate tax filing, claiming undervaluation. The appraiser has been retained to prepare a retrospective locational analysis supporting a defensible effective-date value. Eighteen years of corridor change must be carefully filtered to reflect only what existed at the date of death."}, "location_profile": ["The subject is on Wade Hampton Boulevard in Taylors, northeastern Greenville County, approximately 7 miles from downtown Greenville. Wade Hampton Boulevard is a major commercial arterial. At the date of death 18 years ago, the corridor included older retail, auto-oriented commercial uses, and lower-density residential adjacency — the land use mix it has maintained through to today, though with more reinvestment in recent years.", "At the date of death, the subject fronted on Wade Hampton Boulevard with a 32-foot setback. Traffic volume was significant 18 years ago, as today. The Wade Hampton/Eastside school zone — above-average in Greenville County — applied at the date of death and applies today. A Duke Energy substation operated approximately 0.4 miles north of the subject 18 years ago and continues to operate today. A large vacant industrial parcel approximately 0.2 miles south was present at the date of death and has since been redeveloped into a mixed retail and medical office complex approximately 9 years ago. FEMA Zone X confirmed at the date of death. The Swamp Rabbit Trail was not yet built 18 years ago."], "factors": [{"id": "A", "label": "Wade Hampton Boulevard arterial frontage (32-ft setback — condition at date of death)"}, {"id": "B", "label": "Wade Hampton/Eastside school district (above average — same at date of death)"}, {"id": "C", "label": "Vacant industrial parcel (~0.2 miles south — condition at date of death)"}, {"id": "D", "label": "Duke Energy substation (~0.4 miles north — condition at date of death)"}, {"id": "E", "label": "Wade Hampton/Eastside school district (above average)"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "Mixed retail and medical office complex (current condition — not present at date of death)"}, {"id": "H", "label": "Swamp Rabbit Trail proximity (current condition — not present 18 years ago)"}, {"id": "I", "label": "HOA amenity or greenspace"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — IRS challenge raises the evidentiary standard. When the IRS challenges an estate tax filing, the retrospective appraisal must be supported by period-specific documentation at a level that can withstand expert scrutiny. Every factor identification must be tied to historical evidence — period aerial photography, MLS records, FEMA FIRM maps applicable at the date of death, SCDOT traffic count data from 18 years ago, and contemporaneous market reports. Recollection and inference are not sufficient.", "Teaching Point 2 — Both distractors represent post-death improvements. Factor G (mixed retail/medical complex) replaced a negative condition. Factor H (Swamp Rabbit Trail) is a new amenity. Students who check either factor are understating the negative conditions that existed at the effective date — which would support the IRS challenge by producing a higher value. The appraiser retained to defend the original filing must accurately identify the less favorable effective-date conditions, not today''s improved ones.", "Teaching Point 3 — Vacant industrial land and active substation are distinct locational factors. Factor C (vacant industrial parcel) affects buyer confidence and land use context. Factor D (substation) affects electromagnetic proximity perception at a distance. Students who collapse these into a single ''industrial character'' factor are losing analytical precision. In an IRS challenge, the ability to independently support each factor identification with specific evidence is what makes the retrospective analysis defensible."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a major commercial arterial at 32 feet was a Negative at the date of death — high traffic volume, noise, and commercial character concerns existed then as they do today."}, "B": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive buyer reception — applicable at the date of death and unchanged today."}, "C": {"present": true, "classification": "Negative", "rationale": "A large vacant industrial parcel 0.2 miles south represented a land use uncertainty and blighted visual context at the date of death. Vacant industrial land in a residential market context is a Negative — different from an active nuisance but still affecting buyer confidence and comparable pool quality."}, "D": {"present": true, "classification": "Neutral", "rationale": "The substation was present at the date of death and remains today. At 0.4 miles with no direct adjacency, no audible impact, and no easement on the subject lot, the distance attenuates the market impact to Neutral — consistent with similar analysis in other modules."}, "E": {"present": false}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of death."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C3'
  AND s.order_index = 10;

