-- Scenario 1: 318 Earle Street, Greenville — Downtown-Fringe Long-Term Rental Investor
-- Category M2-S5-C4 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '318 Earle Street, Greenville — Downtown-Fringe Long-Term Rental Investor',
  'You are performing a private consulting locational analysis at 318 Earle Street, Greenville, SC 29601. The subject is 3BR/2BA · 1,580 SF · 1948-built SFR (renovated 2017) · Downtown Greenville Fringe. Private consulting assignment. Client is an individual investor evaluating this property as a long-term single-family rental. The investor''s primary questions are: what rental demand drivers support this location, and are there locational negatives that would constrain tenant quality or turnover? Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the investor lens, and write a brief market-supported rationale for each classification. Investor consulting analysis differs from owner-occupant appraisal: rental demand drivers, trajectory signals, and exit-strategy considerations may shift the analytical weight or even the classification of a factor relative to a standard purchase appraisal. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the investor''s stated strategy.'
FROM scenario_categories WHERE code = 'M2-S5-C4';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "318 Earle Street, Greenville, SC 29601", "subject_summary": "3BR/2BA · 1,580 SF · 1948-built SFR (renovated 2017) · Downtown Greenville Fringe", "context_label": "Consulting Context", "context_text": "Private consulting assignment. Client is an individual investor evaluating this property as a long-term single-family rental. The investor''s primary questions are: what rental demand drivers support this location, and are there locational negatives that would constrain tenant quality or turnover?"}, "location_profile": ["The subject is a renovated bungalow in the northern fringe of downtown Greenville, approximately 1.2 miles from the Main Street corridor. The immediate neighborhood is a mix of renovated and unrenovated single-family residences with a small number of investor-owned rentals. GE Power''s Greenville turbine manufacturing campus is approximately 1.5 miles north — one of Greenville County''s largest single-site employers with over 3,000 employees. Prisma Health''s downtown Greenville medical campus is approximately 1.4 miles southeast.", "318 Earle Street is a through-street lot with a 0.13-acre site and a 26-foot setback from Earle Street, which carries moderate residential traffic. The applicable school zone is an average-performing Greenville County district with no documented buyer premium or discount. FEMA Zone X is confirmed. Downtown Greenville retail, dining, and employment amenities are within a 15-minute walk. No HOA exists."], "factors": [{"id": "A", "label": "GE Power employment proximity (~1.5 miles, 3,000+ employees)"}, {"id": "B", "label": "Prisma Health downtown campus proximity (~1.4 miles)"}, {"id": "C", "label": "Downtown Greenville walkable amenity access"}, {"id": "D", "label": "Average school district (no documented premium)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "University or college proximity"}, {"id": "G", "label": "Industrial nuisance or heavy manufacturing adjacency"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Investor analysis foregrounds rental demand drivers. For an owner-occupant, Factors A and B (employment proximity) are important but secondary to school district, subdivision quality, and lot characteristics. For a rental investor, employment proximity is the primary demand driver — it determines who will rent the property, at what price, and with what tenant stability. Students must shift their analytical lens when the client is an investor.", "Teaching Point 2 — School district classification shifts by client type. Factor D is Neutral in an investor-rental context because the target tenant segment is professional workers, not families with school-age children. The same factor would likely be classified Positive or Negative for an owner-occupant analysis in the same location. Classification is not purely property-driven — it is use-and-client-driven within the bounds of market evidence.", "Teaching Point 3 — Walkability is a distinct rental demand factor. Factor C (downtown walkable access) is analytically distinct from employment proximity (A, B). Walkability affects a different dimension of tenant decision-making — lifestyle access, car-free commuting potential, and amenity proximity. Students who collapse walkability into employment proximity are losing a dimension that investors price separately in urban fringe rental markets."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "A major regional employer within 1.5 miles is a documented rental demand driver — professional workers seeking proximity to a primary employer represent a stable, quality tenant pool for a long-term rental investor."}, "B": {"present": true, "classification": "Positive", "rationale": "Healthcare employment proximity is a well-documented rental demand driver. Medical professionals and support staff seeking walkable or short-commute access to the downtown campus represent a reliable investor tenant segment."}, "C": {"present": true, "classification": "Positive", "rationale": "Walkable access to downtown Greenville retail, dining, and employment within 15 minutes is a documented positive rental demand driver for the professional renter segment that anchors investor returns at this location."}, "D": {"present": true, "classification": "Neutral", "rationale": "Average school performance with no documented premium is Neutral in an investor-rental context targeting professional tenants without school-age children. School district is less analytically prominent for this investor use than for owner-occupant analysis."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement for either the owner or tenant, which supports rental marketability and lender underwriting."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C4'
  AND s.order_index = 1;

