-- Scenario 2: 847 Pine Street, Spartanburg — Healthcare Worker Rental Near Spartanburg Regional
-- Category M2-S5-C4 #2 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'introductory',
  '847 Pine Street, Spartanburg — Healthcare Worker Rental Near Spartanburg Regional',
  'You are performing a private consulting locational analysis at 847 Pine Street, Spartanburg, SC 29303. The subject is 3BR/2BA · 1,660 SF · 1962-built SFR (updated 2014) · Medical District Fringe. Private consulting assignment. Client is a real estate investor evaluating this property as a long-term single-family rental. The subject is near Spartanburg Regional Medical Center. The investor wants to understand whether the location supports stable healthcare worker rental demand and whether any locational negatives would impair marketability or rental pricing. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the investor lens, and write a brief market-supported rationale for each classification. Investor consulting analysis differs from owner-occupant appraisal: rental demand drivers, trajectory signals, and exit-strategy considerations may shift the analytical weight or even the classification of a factor relative to a standard purchase appraisal. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the investor''s stated strategy.'
FROM scenario_categories WHERE code = 'M2-S5-C4';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Pine Street, Spartanburg, SC 29303", "subject_summary": "3BR/2BA · 1,660 SF · 1962-built SFR (updated 2014) · Medical District Fringe", "context_label": "Consulting Context", "context_text": "Private consulting assignment. Client is a real estate investor evaluating this property as a long-term single-family rental. The subject is near Spartanburg Regional Medical Center. The investor wants to understand whether the location supports stable healthcare worker rental demand and whether any locational negatives would impair marketability or rental pricing."}, "location_profile": ["The subject is located approximately 0.4 miles from Spartanburg Regional Medical Center, Spartanburg''s primary acute care hospital and one of the largest employers in Spartanburg County with approximately 5,000 employees. The immediate neighborhood is a mix of single-family residences, some converted to rental use, and small professional office buildings. A few commercial properties along Pine Street reflect the corridor''s proximity to the medical campus.", "847 Pine Street is a through-street lot with a 0.15-acre site and a 22-foot setback. Pine Street carries moderate traffic associated with the nearby medical campus during shift changes. The school zone is below-average for Spartanburg County — not a documented buyer preference driver in this neighborhood. FEMA Zone X is confirmed. USC Upstate''s Spartanburg campus is approximately 2 miles east — a secondary employment and student demand source. No HOA exists."], "factors": [{"id": "A", "label": "Spartanburg Regional Medical Center proximity (~0.4 miles, ~5,000 employees)"}, {"id": "B", "label": "Medical campus shift-change traffic on Pine Street"}, {"id": "C", "label": "Below-average school district"}, {"id": "D", "label": "USC Upstate campus proximity (~2 miles, secondary demand)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "HOA amenity or common area"}, {"id": "G", "label": "Lake or water amenity proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — School district is Negative for investors too, but for a different reason. Factor C is Negative in this investor context not because it deters tenants (the target tenant is a healthcare worker without school-age children) but because it constrains the resale exit market. A below-average school zone limits the pool of owner-occupant buyers when the investor eventually sells, which affects long-term hold value. This is a more sophisticated analytical reason than the owner-occupant version, but the classification is the same.", "Teaching Point 2 — Demand source diversification matters. Factor D (USC Upstate) is a secondary demand source that adds investor value independently of the primary medical driver. A property with two distinct tenant segments — healthcare workers and university-affiliated renters — has more stable rental demand than a single-source property. Students who omit Factor D are missing an investor-relevant consideration not present in owner-occupant analysis.", "Teaching Point 3 — Traffic from an employment driver is still a residential negative. Factor B (shift-change traffic) is a direct consequence of the same hospital that creates the Positive in Factor A. Both must be identified. The positive employment demand driver and the negative residential traffic externality coexist and must be analyzed independently — a pattern students will encounter repeatedly in investor-focused assignments near major employment campuses."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Sub-half-mile proximity to a 5,000-employee hospital is a primary rental demand driver for healthcare workers seeking short-commute housing. This proximity is a strong and documentable Positive for a long-term rental investment strategy."}, "B": {"present": true, "classification": "Negative", "rationale": "Moderate through-traffic during medical shift changes introduces a measurable negative residential amenity concern — a Negative that constrains the owner-occupant buyer pool and slightly narrows the rental tenant pool to those who accept the corridor character."}, "C": {"present": true, "classification": "Negative", "rationale": "Below-average school zone is a Negative even in an investor-rental context because it constrains the owner-occupant resale market, affecting the investor''s exit strategy and long-term hold value."}, "D": {"present": true, "classification": "Positive", "rationale": "USC Upstate at 2 miles provides a secondary rental demand source from students and university staff. A supportive positive for investor demand diversification, though less proximate than the medical campus driver."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement supports both rental marketability and investor financing terms."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C4'
  AND s.order_index = 2;

