INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "412 Riverside Drive, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,840 SF · 2004-built SFR · Riverside Commons", "context_label": "Consulting Context", "context_text": "Private consulting assignment. Client is a buy-and-hold investor evaluating this property for long-term single-family rental. The Greer/Duncan submarket has an active international worker rental segment driven by BMW Manufacturing and its supplier ecosystem. The investor wants to understand whether this location supports that demand base and what locational factors affect long-term hold value."}, "location_profile": ["Riverside Commons is a residential subdivision of approximately 165 homes in Greer, developed 2001–2008, approximately 3.5 miles from BMW Manufacturing''s main campus on SC-101. BMW is the Upstate''s largest employer with over 11,000 direct employees and a significant international workforce. Buyers'' agents and property managers active in the Greer/Duncan submarket consistently identify BMW proximity as the primary rental demand driver for the international worker tenant segment.", "412 Riverside Drive is a corner lot of 0.28 acres at the intersection of Riverside Drive and Commons Court, with street exposure on two sides. I-85 is accessible via SC-101 approximately 2.5 miles east — a significant connectivity positive for the BMW commuter tenant. The subject is in the Greer school attendance zone, above-average in Greenville County with documented positive reception among corporate relocation families. FEMA Zone X is confirmed. A Duke Energy transmission line easement runs along the rear property line."], "factors": [{"id": "A", "label": "BMW Manufacturing proximity (~3.5 miles, primary employer)"}, {"id": "B", "label": "I-85 / SC-101 regional connectivity (~2.5 miles)"}, {"id": "C", "label": "Corner lot location"}, {"id": "D", "label": "Greer school district (above average)"}, {"id": "E", "label": "Transmission line easement along rear lot line"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "University or college proximity"}, {"id": "H", "label": "Military installation proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — School district is Positive when the target tenant has school-age children. Unlike Scenarios 1 and 2 where school district was Neutral or a resale concern, the BMW international worker family segment includes school-age children for whom school quality is a documented rental selection factor. Classification follows the target tenant profile, which follows the dominant demand driver. Students must connect Factor A (BMW proximity) to Factor D (school district) to produce a complete investor analysis.", "Teaching Point 2 — Corner lot is Market-Dependent for investors and owner-occupants alike. The corner lot classification does not change based on investor vs. owner-occupant context — buyer and tenant response is genuinely split in either case. Market-Dependent requires paired sales or rental comparables from the Greer submarket to establish direction. Students who default to Positive for additional yard space or Negative for street exposure are making unsupported directional calls.", "Teaching Point 3 — Transmission easement affects resale exit as well as current value. Factor E is a Negative not only because it constrains tenant appeal but because it constrains the eventual owner-occupant resale pool. Investors must evaluate locational negatives through two lenses: current rental demand impact and long-term exit value impact. Both lenses point to Negative for a rear lot line transmission easement."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "BMW is the Upstate''s largest employer and the documented primary rental demand driver for the international worker segment in the Greer/Duncan submarket. Sub-4-mile proximity is a strong and documentable Positive for an investor targeting this demand base."}, "B": {"present": true, "classification": "Positive", "rationale": "I-85 access within 2.5 miles via SC-101 is a Positive for BMW commuters and the broader regional employment base — a connectivity attribute that supports tenant demand beyond a single employer."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "Corner lots produce split tenant and buyer response — some value the larger site; others are deterred by dual street exposure and reduced privacy. Market-Dependent is appropriate; direction requires paired sales or rental comparables from this submarket."}, "D": {"present": true, "classification": "Positive", "rationale": "Above-average school zone is a Positive for the corporate relocation family segment — an important investor consideration in a market where BMW international worker families with school-age children are a primary tenant profile."}, "E": {"present": true, "classification": "Negative", "rationale": "A transmission easement on the rear lot line is a documented Negative — visual impact, buyer resistance, and reduced privacy are consistent market findings. This constrains both tenant acceptance and long-term resale value."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement supports tenant affordability and investor financing."}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
