-- Scenario 9: 412 Stone Avenue, Greenville — Stone Avenue Dual-Strategy LTR + STR
-- Category M2-S5-C4 #9 · difficulty 'expert'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 9,
  'expert',
  '412 Stone Avenue, Greenville — Stone Avenue Dual-Strategy LTR + STR',
  'You are performing a private consulting locational analysis at 412 Stone Avenue, Greenville, SC 29609. The subject is 3BR/2BA · 1,460 SF · 1940-built SFR (renovated 2022) · Stone Avenue Corridor. Private consulting assignment. Client is a sophisticated investor evaluating this property for a mixed long-term rental and potential short-term rental strategy. Stone Avenue is an established urban corridor with strong employment and amenity proximity. The investor requires analysis of all rental demand drivers, trajectory signals, and any regulatory or use-right factors that affect long-term hold value and exit strategy. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the investor lens, and write a brief market-supported rationale for each classification. Investor consulting analysis differs from owner-occupant appraisal: rental demand drivers, trajectory signals, and exit-strategy considerations may shift the analytical weight or even the classification of a factor relative to a standard purchase appraisal. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the investor''s stated strategy.'
FROM scenario_categories WHERE code = 'M2-S5-C4';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "412 Stone Avenue, Greenville, SC 29609", "subject_summary": "3BR/2BA · 1,460 SF · 1940-built SFR (renovated 2022) · Stone Avenue Corridor", "context_label": "Consulting Context", "context_text": "Private consulting assignment. Client is a sophisticated investor evaluating this property for a mixed long-term rental and potential short-term rental strategy. Stone Avenue is an established urban corridor with strong employment and amenity proximity. The investor requires analysis of all rental demand drivers, trajectory signals, and any regulatory or use-right factors that affect long-term hold value and exit strategy."}, "location_profile": ["The subject is located on Stone Avenue in midtown Greenville, approximately 0.7 miles from the Main Street downtown corridor and 0.9 miles from Prisma Health''s downtown Greenville medical campus. The Stone Avenue corridor has experienced consistent reinvestment since 2014 — documented in permit records, rising median prices, and new independent retail openings along the corridor. The corridor is within the City of Greenville''s STR overlay zone, where short-term rental licensing is available subject to conditional use review.", "412 Stone Avenue is a through-street lot with a 20-foot setback from Stone Avenue, which carries moderate urban traffic. The Swamp Rabbit Trail is 0.4 miles east with on-street connectivity. The subject is in a below-average Greenville County school zone. FEMA Zone X is confirmed. A mixed-use development project has been approved for a vacant parcel approximately 0.2 miles north — first phase residential density and ground-floor retail, with construction anticipated to begin within 12 months. The City of Greenville is currently reviewing proposed amendments to its STR ordinance that may add licensing caps in residential zones. No HOA exists."], "factors": [{"id": "A", "label": "Downtown Greenville proximity (0.7 miles, walkable)"}, {"id": "B", "label": "Prisma Health medical campus proximity (~0.9 miles)"}, {"id": "C", "label": "Swamp Rabbit Trail access (~0.4 miles)"}, {"id": "D", "label": "Approved mixed-use development (~0.2 miles north, construction within 12 months)"}, {"id": "E", "label": "STR licensing available in City overlay zone (current condition)"}, {"id": "F", "label": "STR ordinance under active review (proposed residential licensing caps)"}, {"id": "G", "label": "Stone Avenue improving trajectory (documented, 2014-present)"}, {"id": "H", "label": "Below-average school district"}, {"id": "I", "label": "FEMA Zone X"}, {"id": "J", "label": "HOA restrictions limiting rental use"}, {"id": "K", "label": "Industrial adjacency or manufacturing nuisance"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Regulatory use-right factors are distinct from physical locational factors. Factors E and F are both present and both analytically important, yet they address the same STR use right from opposite directions — E establishes the current right; F identifies the risk of losing it. Students must identify both independently. Conflating them into a single factor loses the distinction between a current condition and a regulatory risk, which an investor needs to price separately in a hold-value analysis.", "Teaching Point 2 — Improving trajectory and structural negatives coexist without canceling. Factor G (improving trajectory) and Factor H (below-average school zone) are simultaneously present. The trajectory improvement may narrow the school zone constraint over time, but in the current analysis they are independent and both must appear. Sophisticated investors understand that trajectory does not eliminate structural constraints — it changes their time horizon.", "Teaching Point 3 — Dual-strategy analysis requires identifying factors through both lenses simultaneously. This scenario requires classifying factors through both the long-term rental lens and the STR lens at the same time. Factor C (trail access) is positive for both; Factor F (STR regulatory risk) is negative for the STR lens only. Students who analyze only one strategy dimension are producing a partial consulting product. Expert-level investor consulting requires holding both lenses simultaneously throughout the analysis."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Walkable downtown Greenville access at 0.7 miles is a primary demand driver for both long-term professional renters and short-term visitors — a Positive that supports both arms of the investor''s dual-strategy."}, "B": {"present": true, "classification": "Positive", "rationale": "Medical employment at 0.9 miles supports the long-term professional rental strategy with a stable healthcare worker tenant base."}, "C": {"present": true, "classification": "Positive", "rationale": "Trail access within 0.4 miles is a documented positive amenity driver in Greenville''s midtown rental and STR markets — a Positive for both tenant segments."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "Approved nearby development introduces future density and retail amenity (positive to some) alongside construction disruption and character change (negative to others). Market-Dependent is appropriate for approved but not yet built development with uncertain net effect on rental demand and hold value."}, "E": {"present": true, "classification": "Positive", "rationale": "Current STR licensing availability under the City overlay zone is a Positive for an investor pursuing a dual rental strategy — it represents an existing use right that adds value flexibility."}, "F": {"present": true, "classification": "Negative", "rationale": "Active regulatory review trending toward STR licensing caps in residential zones is a Negative — it represents potential loss of a use right that the investor has specifically factored into the dual-strategy hold thesis."}, "G": {"present": true, "classification": "Positive", "rationale": "Documented corridor reinvestment over 8+ years with rising prices and new retail is a strong improving trajectory classification — a material positive for long-term hold value and exit strategy."}, "H": {"present": true, "classification": "Negative", "rationale": "Below-average school zone constrains the owner-occupant resale exit pool — a Negative for long-term hold value analysis regardless of strong rental demand."}, "I": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "J": {"present": false}, "K": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
